import React, { useState, useEffect } from 'react';
import api from '../services/api';

function Cronometro({ osId }) {
    const [tempoDecorrido, setTempoDecorrido] = useState(0);
    const [status, setStatus] = useState('nao_iniciado');
    const [intervalId, setIntervalId] = useState(null);
    const [acumuladoInicial, setAcumuladoInicial] = useState(0);

    useEffect(() => {
        const fetchTempo = async () => {
            try {
                const res = await api.get(/os//tempo);
                setAcumuladoInicial(res.data.tempo_acumulado_segundos);
                setStatus(res.data.status_tempo);
                if (res.data.status_tempo === 'em_andamento') {
                    iniciarAtualizacao(res.data.tempo_acumulado_segundos);
                } else {
                    setTempoDecorrido(res.data.tempo_acumulado_segundos);
                }
            } catch (err) {
                console.error(err);
            }
        };
        fetchTempo();
        return () => {
            if (intervalId) clearInterval(intervalId);
        };
    }, [osId]);

    const iniciarAtualizacao = (acumuladoBase) => {
        const inicio = Date.now();
        const id = setInterval(() => {
            const diff = Math.floor((Date.now() - inicio) / 1000);
            setTempoDecorrido(acumuladoBase + diff);
        }, 1000);
        setIntervalId(id);
    };

    const handleIniciar = async () => {
        await api.post(/os//iniciar);
        setStatus('em_andamento');
        iniciarAtualizacao(acumuladoInicial);
    };

    const handlePausar = async () => {
        const res = await api.post(/os//pausar);
        clearInterval(intervalId);
        setStatus('pausado');
        setTempoDecorrido(res.data.acumulado);
        setAcumuladoInicial(res.data.acumulado);
        setIntervalId(null);
    };

    const handleRetomar = async () => {
        await api.post(/os//retomar);
        setStatus('em_andamento');
        iniciarAtualizacao(tempoDecorrido);
    };

    const handleFinalizar = async () => {
        await api.post(/os//finalizar);
        if (intervalId) clearInterval(intervalId);
        setStatus('finalizado');
        const res = await api.get(/os//tempo);
        setTempoDecorrido(res.data.tempo_acumulado_segundos);
        setIntervalId(null);
    };

    const formatarTempo = (segundos) => {
        const h = Math.floor(segundos / 3600);
        const m = Math.floor((segundos % 3600) / 60);
        const s = segundos % 60;
      return `${h.toString().padStart(2, '0')}:`;
    };

    return (
        <div style={{ border: '1px solid #ccc', padding: '10px', borderRadius: '8px', margin: '10px 0' }}>
            <h3>Cronômetro: {formatarTempo(tempoDecorrido)}</h3>
            {status === 'nao_iniciado' && <button onClick={handleIniciar}>▶ Iniciar</button>}
            {status === 'em_andamento' && <button onClick={handlePausar}>⏸ Pausar</button>}
            {status === 'pausado' && <button onClick={handleRetomar}>⏵ Retomar</button>}
            {(status === 'em_andamento' || status === 'pausado') && <button onClick={handleFinalizar}>⏹ Finalizar</button>}
            {status === 'finalizado' && <span>✅ Finalizado</span>}
        </div>
    );
}

export default Cronometro;
